{
  "functional_evaluation_plan": {
    "criteria": [
      {
        "functional_requirement_id": "US-007",
        "evaluation_method": "Role-Based Access Control (RBAC) Integration Audit",
        "success_condition": "GET /dashboard/campaigns/{id} returns HTTP 403 and error code ACCESS_DENIED for users without Marketing Manager role, ensuring dashboard visibility is restricted strictly by role."
      },
      {
        "functional_requirement_id": "US-010",
        "evaluation_method": "Disaster Recovery Time Verification",
        "success_condition": "GET /health/status returns service_state='restored' within the 15-minute threshold after trigger_event_timestamp, and data_integrity_check_result equals 'passed'."
      },
      {
        "functional_requirement_id": "US-011",
        "evaluation_method": "Transport Security Enforcement Validation",
        "success_condition": "GET /{slug} over HTTP returns HTTP 301/302 redirecting to HTTPS, and GET /{slug} over HTTPS returns HTTP 200 OK without cleartext body logging."
      },
      {
        "functional_requirement_id": "US-015",
        "evaluation_method": "Encrypted Payload Integrity Scan",
        "success_condition": "SELECT FROM storage.raw_tables WHERE id=RETURNED_ID returns encrypted blob only; Decryption with valid key succeeds, and decryption with stale key fails with DECRYPTION_KEY_MISMATCH."
      },
      {
        "functional_requirement_id": "US-016",
        "evaluation_method": "Timeout Condition Handling Verification",
        "success_condition": "GET /short-url/{slug} for timed-out links returns HTTP 408/504 with 'timeout' body, and subsequent requests return identical responses without service crashes."
      }
    ]
  },
  "quality_evaluation_plan": {
    "criteria": [
      {
        "nfr_id": "NFR-001",
        "category": "[performance]",
        "evaluation_tool": "Prometheus/Grafana",
        "threshold": "P95 latency <= 100 ms",
        "measurement_method": "Histogram analysis over rolling 5-minute windows",
        "fallback_if_tool_unavailable": "Manual endpoint latency sampling via CLI"
      },
      {
        "nfr_id": "NFR-002",
        "category": "[availability]",
        "evaluation_tool": "Synthetic Monitoring Agent",
        "threshold": "Monthly uptime >= 99.9%",
        "measurement_method": "Aggregated uptime calculation excluding planned maintenance",
        "fallback_if_tool_unavailable": "Infrastructure health check logs review"
      },
      {
        "nfr_id": "NFR-003",
        "category": "[availability]",
        "evaluation_tool": "Recovery Time Objective (RTO) Drill Suite",
        "threshold": "Recovery Time Objective (RTO) <= 15 minutes",
        "measurement_method": "Comparison of failover timestamp to service restoration timestamp",
        "fallback_if_tool_unavailable": "Manual recovery execution log analysis"
      },
      {
        "nfr_id": "NFR-004",
        "category": "[security]",
        "evaluation_tool": "File System Forensics Scanner",
        "threshold": "Zero plaintext URL occurrences in Postgres files",
        "measurement_method": "Binary search for plaintext URL patterns in data files",
        "fallback_if_tool_unavailable": "Direct inspection of storage logs for plaintext strings"
      },
      {
        "nfr_id": "NFR-005",
        "category": "[observability]",
        "evaluation_tool": "ELK Stack / Fluentd",
        "threshold": "Structured JSON logs, 365-day retention",
        "measurement_method": "Log parser validation and retention policy verification",
        "fallback_if_tool_unavailable": "Tail command on stdout verification"
      },
      {
        "nfr_id": "NFR-006",
        "category": "[security]",
        "evaluation_tool": "SSL Labs / HSTS Validator",
        "threshold": "HTTP redirects to HTTPS, HSTS headers present, TLS 1.2+",
        "measurement_method": "Network traffic capture and header analysis",
        "fallback_if_tool_unavailable": "Browser DevTools Network Tab inspection"
      },
      {
        "nfr_id": "NFR-007",
        "category": "[reliability]",
        "evaluation_tool": "Database Query Validator",
        "threshold": "SELECT slug, COUNT(*) FROM url_mappings GROUP BY slug HAVING COUNT(*) > 1 returns zero",
        "measurement_method": "Execution of uniqueness constraint query",
        "fallback_if_tool_unavailable": "Manual slug list verification"
      },
      {
        "nfr_id": "NFR-008",
        "category": "[compliance]",
        "evaluation_tool": "Purge Verification Script",
        "threshold": "100% of deletion requests purged within 24 hours",
        "measurement_method": "Query mapping table for existence of deleted slugs post-request",
        "fallback_if_tool_unavailable": "Manual database audit review"
      },
      {
        "nfr_id": "NFR-009",
        "category": "[compliance]",
        "evaluation_tool": "GDPR Export Comparator",
        "threshold": "Export file contains 100% of stored link data; zero omission",
        "measurement_method": "Comparison of exported record count vs database record count per user",
        "fallback_if_tool_unavailable": "Manual audit of export file rows"
      },
      {
        "nfr_id": "NFR-010",
        "category": "[reliability]",
        "evaluation_tool": "Backup Job Scheduler Monitor",
        "threshold": "100% daily backups successful, zero replication errors",
        "measurement_method": "Job status log check and replication hash verification",
        "fallback_if_tool_unavailable": "Physical storage verification"
      },
      {
        "nfr_id": "NFR-011",
        "category": "[security]",
        "evaluation_tool": "Network Flow Analyzer",
        "threshold": "Threat indicator blocking latency <= 5 seconds",
        "measurement_method": "Timestamp delta between request and block response",
        "fallback_if_tool_unavailable": "Proxy log analysis"
      },
      {
        "nfr_id": "NFR-012",
        "category": "[scalability]",
        "evaluation_tool": "Load Testing Framework (e.g., K6)",
        "threshold": "1000 requests per IP per 60-second window, excess rejected with 429",
        "measurement_method": "RPS count and HTTP 429 response rate monitoring",
        "fallback_if_tool_unavailable": "Network sniffer request count analysis"
      },
      {
        "nfr_id": "NFR-013",
        "category": "[security]",
        "evaluation_tool": "Threat Feed Integration Monitor",
        "threshold": "Zero malicious URL submissions stored",
        "measurement_method": "Verify storage table contains no entries matching ENT-THREAT-INDICATOR",
        "fallback_if_tool_unavailable": "Database schema integrity check"
      },
      {
        "nfr_id": "NFR-014",
        "category": "[compliance]",
        "evaluation_tool": "Notification Event Logger",
        "threshold": "Notification attempt generated before expiry timestamp; zero missed",
        "measurement_method": "Timestamp comparison of policy event vs notification event",
        "fallback_if_tool_unavailable": "Manual inbox/mailbox check"
      },
      {
        "nfr_id": "NFR-015",
        "category": "[reliability]",
        "evaluation_tool": "Crash Log Analyzer",
        "threshold": "Zero service crashes triggered by timeout conditions",
        "measurement_method": "System log scan for unhandled exceptions during timeout",
        "fallback_if_tool_unavailable": "Process monitoring via OS supervisor tools"
      }
    ]
  },
  "reasoning_evaluation_plan": {
    "scenarios": [
      {
        "id": "REASON-01",
        "description": "Verify system behavior when a deletion request (US-006) is received while a read request (US-002) occurs concurrently on the same slug.",
        "pass_criteria": "Read request returns 404 immediately after deletion commit, with no data consistency errors or race conditions logged."
      },
      {
        "id": "REASON-02",
        "description": "Validate system integrity when a key rotation event occurs (US-015) without losing access to historical data.",
        "pass_criteria": "Decryption with old key fails gracefully, new key succeeds for current data, no data corruption or migration errors."
      },
      {
        "id": "REASON-03",
        "description": "Assess system resilience when a GDPR export request (US-005) is initiated against a dataset with no associated links.",
        "pass_criteria": "System returns HTTP 200 with empty array payload, no 404 error generated, audit log records the export attempt."
      }
    ],
    "ai_subsystems_detected": false
  }
}
